import React, { useState, useEffect } from 'react';

function DataFetcher() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('https://api.example.com/data');
        if (!response.ok) throw new Error('Network response was not ok');
        const result = await response.json();
        setData(result);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []); // Empty dependency array ensures this runs only on mount

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;
  return <div>Data: {JSON.stringify(data)}</div>;
}

export default DataFetcher;
```

**Step-by-step explanation:**

1. **Import hooks**: `useState` for managing component state (data, loading, error) and `useEffect` for side effects.
2. **Initialize state**: `data` starts as `null`, `loading` as `true`, `error` as `null`.
3. **useEffect with empty dependency array**: The callback runs once after the component mounts.
4. **Async fetch inside useEffect**: Define an async function `fetchData` to avoid making the effect callback itself async.
5. **Try-catch-finally**: 
   - `try`: Perform fetch, check response status, parse JSON, and update `data`.
   - `catch`: If any error occurs, set the error message.
   - `finally`: Set `loading` to `false` regardless of success or failure.
6. **Conditional rendering**: Show loading indicator, error message, or the fetched data based on state.

