    onFulfilled = typeof onFulfilled === 'function' ? onFulfilled : v => v;
    onRejected = typeof onRejected === 'function' ? onRejected : r => { throw r; };

    const promise2 = new MyPromise((resolve, reject) => {
      const handleFulfilled = () => {
        queueMicrotask(() => {
          try {
            const x = onFulfilled(this.value);
            resolvePromise(promise2, x, resolve, reject);
          } catch (err) {
            reject(err);
          }
        });
      };

      const handleRejected = () => {
        queueMicrotask(() => {
          try {
            const x = onRejected(this.reason);
            resolvePromise(promise2, x, resolve, reject);
          } catch (err) {
            reject(err);
          }
        });
      };

      if (this.state === 'fulfilled') {
        handleFulfilled();
      } else if (this.state === 'rejected') {
        handleRejected();
      } else {
        this.onFulfilledCallbacks.push(handleFulfilled);
        this.onRejectedCallbacks.push(handleRejected);
      }
    });

    return promise2;
  }

  catch(onRejected) {
    return this.then(null, onRejected);
  }

  finally(callback) {
    return this.then(
      value => MyPromise.resolve(callback()).then(() => value),
      reason => MyPromise.resolve(callback()).then(() => { throw reason; })
    );
  }

  static resolve(value) {
    if (value instanceof MyPromise) return value;
    return new MyPromise(resolve => resolve(value));
  }

  static reject(reason) {
    return new MyPromise((_, reject) => reject(reason));
  }

  static all(promises) {
    return new MyPromise((resolve, reject) => {
      const results = [];
      let completed = 0;
      promises.forEach((p, i) => {
        MyPromise.resolve(p).then(
          val => {
            results[i] = val;
            completed++;
            if (completed === promises.length) resolve(results);
          },
          err => reject(err)
        );
      });
      if (promises.length === 0) resolve(results);
    });
  }

  static race(promises) {
    return new MyPromise((resolve, reject) => {
      promises.forEach(p => {
        MyPromise.resolve(p).then(resolve, reject);
      });
    });
  }
}

function resolvePromise(promise2, x, resolve, reject) {
  if (promise2 === x) {
    return reject(new TypeError('Chaining cycle'));
  }
  if (x instanceof MyPromise) {
    x.then(resolve, reject);
  } else {
    resolve(x);
  }
}

// Examples
const p1 = new MyPromise((resolve) => {
  setTimeout(() => resolve('Hello'), 100);
});
p1.then(val => val + ' World').then(console.log); // "Hello World"

const p2 = new MyPromise((_, reject) => {
  setTimeout(() => reject('Error!'), 50);
});
p2.catch(err => console.log('Caught:', err)); // "Caught: Error!"

MyPromise.all([
  MyPromise.resolve(1),
  MyPromise.resolve(2),
  MyPromise.resolve(3)
]).then(console.log); // [1, 2, 3]

MyPromise.race([
  new MyPromise(resolve => setTimeout(() => resolve('fast'), 10)),
  new MyPromise(resolve => setTimeout(() => resolve('slow'), 100))
]).then(console.log); // "fast"
```

To fix a NullPointerException in Java, always ensure objects are not null before invoking methods or accessing fields. Use null checks, `Optional`, or `Objects.requireNonNull()`.

**Example 1: Null check before method call**
```java
String str = getString(); // may return null
if (str != null) {
    System.out.println(str.length());
} else {
    System.out.println("String is null");
}
```

**Example 2: Using Optional**
```java
Optional<String> optional = Optional.ofNullable(getString());
optional.ifPresent(s -> System.out.println(s.length()));
```

**Example 3: Using Objects.requireNonNull() for parameters**
```java
public void process(String input) {
    this.input = Objects.requireNonNull(input, "input must not be null");
}
```

**Example 4: Defensive programming with ternary**
```java
String result = (obj != null) ? obj.toString() : "default";
```

Always identify the null source (e.g., uninitialized variables, method returns, array elements) and handle accordingly.

**Comparison of Rate Limiting Algorithms**

| Algorithm       | Burst Handling | Accuracy | Memory/CPU | Distributed Suitability |
|-----------------|----------------|----------|------------|-------------------------|
| Fixed Window    | Poor (boundary bursts) | Low | Low | Easy (atomic counters) |
| Sliding Window  | Good (smooth) | High | High (log of timestamps) | Heavy (sorted sets) |
| Token Bucket    | Good (configurable burst) | Medium | Medium (counter + timestamp) | Moderate (sync tokens) |
| Leaky Bucket    | None (constant output) | High | Low (queue) | Hard (global queue) |

**Recommendation: Token Bucket with Local Caching + Periodic Sync**  
- Handles 100M req/min across data centers with low latency.  
- Allows controlled bursts.  
- Uses local token counters (fast) and syncs with a distributed store (e.g., Redis Cluster) every few seconds.  
- Trades exact global limit for availability and performance.

**CAP Theorem Implications**  
- **Partition Tolerance** is mandatory (multiple DCs).  
- Choose **Availability** over **Consistency** (AP): during network splits, local tokens allow continued service, possibly exceeding the limit slightly.  
- Eventual consistency: global limit enforced on average, not strictly.

**Failure Scenarios**  
- **Redis down**: Local tokens continue until exhausted; rate limiting degrades to local-only (may over-allow).  
- **Network partition**: Each DC uses its last synced token count; over-limit possible until partition heals.  
- **High load**: Redis may become bottleneck; use sharding and async writes.

**Consistency Trade-offs**  
- Strong consistency (e.g., using Paxos) ensures exact limit but adds latency and reduces throughput.  
- Eventual consistency (recommended) allows small violations (<5% over-limit) but scales linearly.

**High-Level Pseudocode (Token Bucket, Distributed)**

```
