We'll implement a minimal Promise from scratch, covering states, executor, `then`, `catch`, `finally`, and static methods. The key steps:

1. **State machine**: `PENDING`, `FULFILLED`, `REJECTED`.  
2. **Constructor**: Accepts an executor function that receives `resolve` and `reject`. The executor runs immediately.  
3. **Resolution/rejection**: Transition state, store value/reason, and schedule pending callbacks via microtask (using `queueMicrotask`).  
4. **`then`**: Returns a new Promise. Handles `onFulfilled` and `onRejected`. If state is pending, queues the callbacks; otherwise schedules them. The returned promise resolves with the return value of the handler (or the original value if handler is not a function).  
5. **`catch`**: Shortcut for `then(null, onRejected)`.  
6. **`finally`**: Calls a callback regardless of outcome, then passes through the value/reason.  
7. **Static methods**: `Promise.resolve`, `Promise.reject`, `Promise.all`, `Promise.race`.

Below is the implementation with inline comments.

```javascript
class MyPromise {
  static PENDING = 'PENDING';
  static FULFILLED = 'FULFILLED';
  static REJECTED = 'REJECTED';

  constructor(executor) {
    this.state = MyPromise.PENDING;
    this.value = undefined;
    this.reason = undefined;
    this.onFulfilledCallbacks = [];
    this.onRejectedCallbacks = [];

    const resolve = (value) => {
      if (this.state !== MyPromise.PENDING) return;
      // If value is a thenable, adopt its state
      if (value && typeof value.then === 'function') {
        return value.then(resolve, reject);
      }
      this.state = MyPromise.FULFILLED;
      this.value = value;
      this.onFulfilledCallbacks.forEach(cb => this._schedule(cb));
    };

    const reject = (reason) => {
      if (this.state !== MyPromise.PENDING) return;
      this.state = MyPromise.REJECTED;
      this.reason = reason;
      this.onRejectedCallbacks.forEach(cb => this._schedule(cb));
    };

    try {
      executor(resolve, reject);
    } catch (err) {
      reject(err);
    }
  }

  _schedule(fn) {
    queueMicrotask(fn);
  }

  then(onFulfilled, onRejected) {
    const promise2 = new MyPromise((resolve, reject) => {
      const handleFulfilled = () => {
        try {
          if (typeof onFulfilled !== 'function') {
            resolve(this.value);
          } else {
            const x = onFulfilled(this.value);
            this._resolvePromise(promise2, x, resolve, reject);
          }
        } catch (err) {
          reject(err);
        }
      };

      const handleRejected = () => {
        try {
          if (typeof onRejected !== 'function') {
            reject(this.reason);
          } else {
            const x = onRejected(this.reason);
            this._resolvePromise(promise2, x, resolve, reject);
          }
        } catch (err) {
          reject(err);
        }
      };

      if (this.state === MyPromise.FULFILLED) {
        this._schedule(handleFulfilled);
      } else if (this.state === MyPromise.REJECTED) {
        this._schedule(handleRejected);
      } else {
        this.onFulfilledCallbacks.push(handleFulfilled);
        this.onRejectedCallbacks.push(handleRejected);
      }
    });
    return promise2;
  }

  _resolvePromise(promise2, x, resolve, reject) {
    if (promise2 === x) {
      return reject(new TypeError('Chaining cycle detected'));
    }
    if (x && (typeof x === 'object' || typeof x === 'function')) {
      let called = false;
      try {
        const then = x.then;
        if (typeof then === 'function') {
          then.call(
            x,
            (y) => {
              if (called) return;
              called = true;
              this._resolvePromise(promise2, y, resolve, reject);
            },
            (r) => {
              if (called) return;
              called = true;
              reject(r);
            }
          );
        } else {
          resolve(x);
        }
      } catch (err) {
        if (called) return;
        called = true;
        reject(err);
      }
    } else {
      resolve(x);
    }
  }

  catch(onRejected) {
    return this.then(null, onRejected);
  }

  finally(callback) {
    return this.then(
      (value) => MyPromise.resolve(callback()).then(() => value),
      (reason) => MyPromise.resolve(callback()).then(() => { throw reason; })
    );
  }

  static resolve(value) {
    if (value instanceof MyPromise) return value;
    return new MyPromise((resolve) => resolve(value));
  }

  static reject(reason) {
    return new MyPromise((_, reject) => reject(reason));
  }

  static all(promises) {
    return new MyPromise((resolve, reject) => {
      const results = [];
      let completed = 0;
      promises.forEach((p, i) => {
        MyPromise.resolve(p).then(
          (val) => {
            results[i] = val;
            completed++;
            if (completed === promises.length) resolve(results);
          },
          reject
        );
      });
      if (promises.length === 0) resolve(results);
    });
  }

  static race(promises) {
    return new MyPromise((resolve, reject) => {
      promises.forEach(p => MyPromise.resolve(p).then(resolve, reject));
    });
  }
}
```

This implementation follows the Promises/A+ specification for `then` and handles chaining, async execution, and error propagation.

Event delegation leverages event bubbling: instead of attaching listeners to individual child elements, you attach a single listener to a common ancestor. When an event occurs on a child, it bubbles up to the ancestor, where you check the event target to determine which child triggered it.

Example:
```html
<ul id="list">
  <li>Item 1</li>
  <li>Item 2</li>
  <li>Item 3</li>
</ul>
```
```javascript
document.getElementById('list').addEventListener('click', function(e) {
  if (e.target.tagName === 'LI') {
    console.log('Clicked:', e.target.textContent);
  }
});
```
This handles clicks on existing and future `<li>` elements without adding individual listeners.

