class MyPromise {
  constructor(executor) {
    this._state = 'pending'; // 'pending' | 'fulfilled' | 'rejected'
    this._value = undefined;
    this._reason = undefined;
    this._onFulfilledCallbacks = [];
    this._onRejectedCallbacks = [];

    const resolve = (value) => {
      if (this._state !== 'pending') return;
      this._state = 'fulfilled';
      this._value = value;
      this._executeCallbacks(this._onFulfilledCallbacks, value);
    };

    const reject = (reason) => {
      if (this._state !== 'pending') return;
      this._state = 'rejected';
      this._reason = reason;
      this._executeCallbacks(this._onRejectedCallbacks, reason);
    };

    try {
      executor(resolve, reject);
    } catch (err) {
      reject(err);
    }
  }

  _executeCallbacks(callbacks, value) {
    // Use microtask to simulate async behavior
    queueMicrotask(() => {
      callbacks.forEach(cb => cb(value));
    });
  }

  then(onFulfilled, onRejected) {
    const promise2 = new MyPromise((resolve, reject) => {
      const handleFulfilled = (value) => {
        try {
          if (typeof onFulfilled !== 'function') {
            resolve(value);
          } else {
            const x = onFulfilled(value);
            this._resolvePromise(promise2, x, resolve, reject);
          }
        } catch (err) {
          reject(err);
        }
      };

      const handleRejected = (reason) => {
        try {
          if (typeof onRejected !== 'function') {
            reject(reason);
          } else {
            const x = onRejected(reason);
            this._resolvePromise(promise2, x, resolve, reject);
          }
        } catch (err) {
          reject(err);
        }
      };

      if (this._state === 'fulfilled') {
        queueMicrotask(() => handleFulfilled(this._value));
      } else if (this._state === 'rejected') {
        queueMicrotask(() => handleRejected(this._reason));
      } else {
        this._onFulfilledCallbacks.push(handleFulfilled);
        this._onRejectedCallbacks.push(handleRejected);
      }
    });
    return promise2;
  }

  _resolvePromise(promise2, x, resolve, reject) {
    if (promise2 === x) {
      reject(new TypeError('Chaining cycle detected'));
      return;
    }

    if (x instanceof MyPromise) {
      x.then(
        value => this._resolvePromise(promise2, value, resolve, reject),
        reason => reject(reason)
      );
    } else if (x !== null && (typeof x === 'object' || typeof x === 'function')) {
      let called = false;
      try {
        const then = x.then;
        if (typeof then === 'function') {
          then.call(
            x,
            y => {
              if (called) return;
              called = true;
              this._resolvePromise(promise2, y, resolve, reject);
            },
            r => {
              if (called) return;
              called = true;
              reject(r);
            }
          );
        } else {
          resolve(x);
        }
      } catch (err) {
        if (!called) {
          called = true;
          reject(err);
        }
      }
    } else {
      resolve(x);
    }
  }

  catch(onRejected) {
    return this.then(null, onRejected);
  }

  finally(callback) {
    return this.then(
      value => MyPromise.resolve(callback()).then(() => value),
      reason => MyPromise.resolve(callback()).then(() => { throw reason; })
    );
  }

  static resolve(value) {
    if (value instanceof MyPromise) return value;
    return new MyPromise(resolve => resolve(value));
  }

  static reject(reason) {
    return new MyPromise((_, reject) => reject(reason));
  }

  static all(promises) {
    return new MyPromise((resolve, reject) => {
      const results = [];
      let completed = 0;
      promises.forEach((p, i) => {
        MyPromise.resolve(p).then(
          value => {
            results[i] = value;
            completed++;
            if (completed === promises.length) resolve(results);
          },
          reject
        );
      });
      if (promises.length === 0) resolve(results);
    });
  }

  static race(promises) {
    return new MyPromise((resolve, reject) => {
      promises.forEach(p => {
        MyPromise.resolve(p).then(resolve, reject);
      });
    });
  }
}

// ---------- Examples ----------

// Basic usage
const p1 = new MyPromise((resolve, reject) => {
  setTimeout(() => resolve('Hello'), 100);
});
p1.then(value => console.log(value)); // 'Hello' after 100ms

// Chaining
const p2 = new MyPromise((resolve) => resolve(1));
p2.then(v => v + 1)
  .then(v => v * 2)
  .then(v => console.log(v)); // 4

// Error handling
const p3 = new MyPromise((_, reject) => reject('Error!'));
p3.catch(err => console.log(err)); // 'Error!'

// Static methods
MyPromise.resolve(42).then(v => console.log(v)); // 42
MyPromise.reject('fail').catch(e => console.log(e)); // 'fail'

// Promise.all
const p4 = MyPromise.resolve(1);
const p5 = MyPromise.resolve(2);
MyPromise.all([p4, p5]).then(v => console.log(v)); // [1, 2]

// Promise.race
const p6 = new MyPromise(resolve => setTimeout(() => resolve('fast'), 100));
const p7 = new MyPromise(resolve => setTimeout(() => resolve('slow'), 200));
MyPromise.race([p6, p7]).then(v => console.log(v)); // 'fast'
