The component renders infinitely due to a state update triggered during render or in a `useEffect` without proper dependency array, causing a re-render loop.

**Example 1: State update in render**
```jsx
function InfiniteRender() {
  const [count, setCount] = useState(0);
  setCount(count + 1); // Called every render → infinite loop
  return <div>{count}</div>;
}
```

**Example 2: `useEffect` without dependencies**
```jsx
function InfiniteRender() {
  const [count, setCount] = useState(0);
  useEffect(() => {
    setCount(count + 1); // Runs after every render → infinite loop
  }); // Missing dependency array
  return <div>{count}</div>;
}
```

**Example 3: Incorrect dependency in `useEffect`**
```jsx
function InfiniteRender() {
  const [count, setCount] = useState(0);
  useEffect(() => {
    setCount(prev => prev + 1);
  }, [count]); // count changes → effect runs → count changes → ...
  return <div>{count}</div>;
}
```

```jsx
import React, { useState, useEffect } from 'react';

function DataFetcher() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('https://api.example.com/data')
      .then(response => {
        if (!response.ok) throw new Error('Network response was not ok');
        return response.json();
      })
      .then(data => {
        setData(data);
        setLoading(false);
      })
      .catch(error => {
        setError(error.message);
        setLoading(false);
      });
  }, []);

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;
  return <div>Data: {JSON.stringify(data)}</div>;
}

export default DataFetcher;
