import React, { useState, useEffect } from 'react';

function DataFetchingComponent() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('https://api.example.com/data');
        if (!response.ok) throw new Error('Network response was not ok');
        const result = await response.json();
        setData(result);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []); // Empty dependency array ensures this runs only on mount

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;
  return <div>Data: {JSON.stringify(data)}</div>;
}

export default DataFetchingComponent;
```

**Step-by-step explanation:**

1. **Import hooks**: `useState` for state management, `useEffect` for side effects.
2. **Define state variables**: `data` (fetched result), `loading` (initial true), `error` (null).
3. **Use `useEffect` with empty dependency array** to run the fetch only once when the component mounts.
4. **Inside `useEffect`**, define an async function `fetchData` to handle the fetch, error handling, and state updates.
5. **Call `fetchData()`** immediately inside the effect.
6. **Conditional rendering**: Show loading, error, or the fetched data based on state.

