class MyPromise {
  constructor(executor) {
    this._state = 'pending'; // 'pending' | 'fulfilled' | 'rejected'
    this._value = undefined;
    this._handlers = []; // [{ onFulfilled, onRejected, resolve, reject }]

    const resolve = (value) => this._resolve(value);
    const reject = (reason) => this._reject(reason);

    try {
      executor(resolve, reject);
    } catch (err) {
      reject(err);
    }
  }

  _resolve(value) {
    if (this._state !== 'pending') return;
    if (value && typeof value.then === 'function') {
      // thenable – unwrap
      const then = value.then;
      try {
        then.call(value, this._resolve.bind(this), this._reject.bind(this));
      } catch (err) {
        this._reject(err);
      }
      return;
    }
    this._state = 'fulfilled';
    this._value = value;
    this._executeHandlers();
  }

  _reject(reason) {
    if (this._state !== 'pending') return;
    this._state = 'rejected';
    this._value = reason;
    this._executeHandlers();
  }

  _executeHandlers() {
    // schedule microtask to avoid synchronous execution
    queueMicrotask(() => {
      const handlers = this._handlers;
      this._handlers = []; // clear after execution
      for (const handler of handlers) {
        this._handle(handler);
      }
    });
  }

  _handle(handler) {
    const { onFulfilled, onRejected, resolve, reject } = handler;
    let callback;
    let value;

    if (this._state === 'fulfilled') {
      callback = onFulfilled;
      value = this._value;
    } else if (this._state === 'rejected') {
      callback = onRejected;
      value = this._value;
    } else {
      // should not happen
      return;
    }

    if (typeof callback !== 'function') {
      // pass through
      if (this._state === 'fulfilled') resolve(value);
      else reject(value);
      return;
    }

    try {
      const result = callback(value);
      resolve(result);
    } catch (err) {
      reject(err);
    }
  }

  then(onFulfilled, onRejected) {
    return new MyPromise((resolve, reject) => {
      const handler = { onFulfilled, onRejected, resolve, reject };
      if (this._state === 'pending') {
        this._handlers.push(handler);
      } else {
        // schedule microtask for consistency
        queueMicrotask(() => this._handle(handler));
      }
    });
  }

  catch(onRejected) {
    return this.then(null, onRejected);
  }

  finally(onFinally) {
    return this.then(
      value => MyPromise.resolve(onFinally()).then(() => value),
      reason => MyPromise.resolve(onFinally()).then(() => { throw reason; })
    );
  }

  static resolve(value) {
    if (value instanceof MyPromise) return value;
    return new MyPromise(resolve => resolve(value));
  }

  static reject(reason) {
    return new MyPromise((_, reject) => reject(reason));
  }

  static all(promises) {
    return new MyPromise((resolve, reject) => {
      const results = [];
      let completed = 0;
      if (promises.length === 0) resolve(results);
      promises.forEach((p, i) => {
        MyPromise.resolve(p).then(
          value => {
            results[i] = value;
            completed++;
            if (completed === promises.length) resolve(results);
          },
          reject
        );
      });
    });
  }

  static race(promises) {
    return new MyPromise((resolve, reject) => {
      promises.forEach(p => MyPromise.resolve(p).then(resolve, reject));
    });
  }

  static allSettled(promises) {
    return new MyPromise(resolve => {
      const results = [];
      let completed = 0;
      if (promises.length === 0) resolve(results);
      promises.forEach((p, i) => {
        MyPromise.resolve(p).then(
          value => { results[i] = { status: 'fulfilled', value }; completed++; if (completed === promises.length) resolve(results); },
          reason => { results[i] = { status: 'rejected', reason }; completed++; if (completed === promises.length) resolve(results); }
        );
      });
    });
  }

  static any(promises) {
    return new MyPromise((resolve, reject) => {
      const errors = [];
      let rejectedCount = 0;
      if (promises.length === 0) reject(new AggregateError([], 'All promises were rejected'));
      promises.forEach((p, i) => {
        MyPromise.resolve(p).then(resolve, reason => {
          errors[i] = reason;
          rejectedCount++;
          if (rejectedCount === promises.length) reject(new AggregateError(errors, 'All promises were rejected'));
        });
      });
    });
  }
}
