// Async resolution
const p2 = new MyPromise(resolve => {
  setTimeout(() => resolve('Async'), 0);
});
p2.then(console.log); // "Async"

// Static methods
MyPromise.resolve(42).then(console.log); // 42
MyPromise.reject('fail').catch(console.log); // "fail"

// Promise.all
MyPromise.all([
  MyPromise.resolve(1),
  new MyPromise(resolve => setTimeout(() => resolve(2), 50)),
  3
]).then(console.log); // [1, 2, 3]

// Promise.race
