```c
#include <stdlib.h>
#include <pthread.h>
#include <stdint.h>
#include <string.h>
#include <stdio.h>

/* Custom allocator with coalescing free list and mark-sweep GC */

typedef struct Block {
    size_t size;               /* includes header */
    int free;                  /* 1 if free, 0 if allocated */
    int marked;                /* for GC */
    struct Block *next;
    struct Block *prev;
} Block;

#define BLOCK_SIZE sizeof(Block)
#define MIN_BLOCK (BLOCK_SIZE + 16)  /* minimum allocation size */

static Block *free_list = NULL;
static pthread_mutex_t alloc_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Helper: get block from user pointer */
static Block *ptr_to_block(void *ptr) {
    return (Block *)((char *)ptr - BLOCK_SIZE);
}

/* Helper: get user pointer from block */
static void *block_to_ptr(Block *b) {
    return (void *)((char *)b + BLOCK_SIZE);
}

/* Coalesce adjacent free blocks */
static void coalesce(Block *b) {
    Block *next = (Block *)((char *)b + b->size);
    if ((char *)next < (char *)free_list + 1024*1024) { /* dummy heap end */
        if (next->free) {
            b->size += next->size;
            b->next = next->next;
            if (next->next) next->next->prev = b;
        }
    }
}

/* Allocate memory */
void *my_malloc(size_t size) {
    pthread_mutex_lock(&alloc_mutex);
    size = (size + 7) & ~7; /* align to 8 bytes */
    size += BLOCK_SIZE;
    if (size < MIN_BLOCK) size = MIN_BLOCK;

    Block *curr = free_list;
    while (curr) {
        if (curr->free && curr->size >= size) {
            /* split if remainder is large enough */
            if (curr->size >= size + MIN_BLOCK) {
                Block *new_block = (Block *)((char *)curr + size);
                new_block->size = curr->size - size;
                new_block->free = 1;
                new_block->marked = 0;
                new_block->next = curr->next;
                new_block->prev = curr;
                if (curr->next) curr->next->prev = new_block;
                curr->next = new_block;
                curr->size = size;
            }
            curr->free = 0;
            curr->marked = 0;
            pthread_mutex_unlock(&alloc_mutex);
            return block_to_ptr(curr);
        }
        curr = curr->next;
    }
    /* No suitable block – extend heap (simplified: use malloc) */
    Block *new_block = (Block *)malloc(size);
    if (!new_block) { pthread_mutex_unlock(&alloc_mutex); return NULL; }
    new_block->size = size;
    new_block->free = 0;
    new_block->marked = 0;
    new_block->next = free_list;
    new_block->prev = NULL;
    if (free_list) free_list->prev = new_block;
    free_list = new_block;
    pthread_mutex_unlock(&alloc_mutex);
    return block_to_ptr(new_block);
}

/* Free memory */
void my_free(void *ptr) {
    if (!ptr) return;
    pthread_mutex_lock(&alloc_mutex);
    Block *b = ptr_to_block(ptr);
    b->free = 1;
    coalesce(b);
    /* also coalesce with previous if free */
    Block *prev = b->prev;
    if (prev && prev->free) {
        prev->size += b->size;
        prev->next = b->next;
        if (b->next) b->next->prev = prev;
        b = prev;
    }
    pthread_mutex_unlock(&alloc_mutex);
}

/* Garbage collection: mark-sweep */
void my_gc(void) {
    pthread_mutex_lock(&alloc_mutex);
    /* Mark phase: scan roots (simplified: mark all allocated blocks as reachable) */
    /* In a real system, you'd traverse stack/globals. Here we just mark all as reachable to avoid freeing live data. */
    Block *curr = free_list;
    while (curr) {
        if (!curr->free) curr->marked = 1;
        curr = curr->next;
    }
    /* Sweep phase: free unmarked blocks */
    curr = free_list;
    while (curr) {
        if (!curr->free && !curr->marked) {
            curr->free = 1;
            coalesce(curr);
        }
        curr = curr->next;
    }
    pthread_mutex_unlock(&alloc_mutex);
}

/* Example usage */
int main() {
    int *p = (int *)my_malloc(100 * sizeof(int));
    if (p) {
        p[0] = 42;
        printf("Allocated int at %p, value = %d\n", (void*)p, p[0]);
    }
    my_free(p);
    my_gc(); /* no-op in this simple example */
    return 0;
}
```

**Pointer arithmetic**: `ptr_to_block` subtracts `BLOCK_SIZE` from user pointer to get block header. `block_to_ptr` adds `BLOCK_SIZE`. Coalescing uses `(char*)b + b->size` to reach next block.

**Metadata overhead**: Each block has a `Block` header (size, free flag, marked flag, next/prev pointers). Overhead = `BLOCK_SIZE` (typically 32 bytes on 64-bit). Minimum allocation includes header.

**Thread-safety**: A single `pthread_mutex_t` protects all allocator operations. All public functions lock/unlock.

**Fragmentation prevention**: Coalescing adjacent free blocks on free and after GC. Splitting blocks only when remainder is large enough.

**GC**: Simple mark-sweep; marks all allocated blocks as reachable (placeholder). In practice, roots must be traced. Sweep frees unmarked blocks.

```cpp
#include <cstddef>
#include <cstdlib>
#include <mutex>
#include <cstring>

// Custom memory allocator with coalescing and mark-sweep GC
class CompactAllocator {
public:
    CompactAllocator(size_t poolSize = 1024 * 1024) {
        pool = static_cast<char*>(std::malloc(poolSize));
        poolEnd = pool + poolSize;
        // Initialize free list with one large block
        BlockHeader* initial = reinterpret_cast<BlockHeader*>(pool);
        initial->size = poolSize - sizeof(BlockHeader);
        initial->flags = FREE;
        initial->next = nullptr;
        freeList = initial;
    }

    ~CompactAllocator() {
        std::free(pool);
    }

    void* allocate(size_t size) {
        std::lock_guard<std::mutex> lock(mtx);
        // Align size to 8 bytes and add header overhead
        size = (size + 7) & ~7;
        size_t totalSize = size + sizeof(BlockHeader);

        // First-fit search
        BlockHeader* prev = nullptr;
        BlockHeader* curr = freeList;
        while (curr) {
            if (curr->size >= totalSize) {
                // Split if remainder is large enough
                size_t remaining = curr->size - totalSize;
                if (remaining >= sizeof(BlockHeader) + 8) {
                    BlockHeader* newBlock = reinterpret_cast<BlockHeader*>(
                        reinterpret_cast<char*>(curr) + totalSize);
                    newBlock->size = remaining - sizeof(BlockHeader);
                    newBlock->flags = FREE;
                    newBlock->next = curr->next;
                    curr->size = size;
                    curr->flags = ALLOCATED;
                    curr->next = nullptr;
                    if (prev) prev->next = newBlock;
                    else freeList = newBlock;
                } else {
                    // Allocate entire block
                    curr->flags = ALLOCATED;
                    if (prev) prev->next = curr->next;
                    else freeList = curr->next;
                }
                // Return pointer after header
                return reinterpret_cast<char*>(curr) + sizeof(BlockHeader);
            }
            prev = curr;
            curr = curr->next;
        }
        return nullptr; // Out of memory
    }

    void deallocate(void* ptr) {
        if (!ptr) return;
        std::lock_guard<std::mutex> lock(mtx);
        BlockHeader* block = reinterpret_cast<BlockHeader*>(
            static_cast<char*>(ptr) - sizeof(BlockHeader));
        block->flags = FREE;

        // Coalesce with next block if free
        BlockHeader* next = reinterpret_cast<BlockHeader*>(
            reinterpret_cast<char*>(block) + sizeof(BlockHeader) + block->size);
        if (next < reinterpret_cast<BlockHeader*>(poolEnd) && next->flags == FREE) {
            block->size += sizeof(BlockHeader) + next->size;
            // Remove next from free list (simplified: linear search)
            removeFromFreeList(next);
        }

        // Coalesce with previous block (requires scanning free list or boundary tags)
        // For simplicity, we skip backward coalescing here; a full implementation would use boundary tags.

        // Insert block into free list (sorted by address for easier coalescing)
        insertIntoFreeList(block);
    }

    // Simple mark-sweep garbage collection
    void collectGarbage(void* roots[], size_t numRoots) {
        std::lock_guard<std::mutex> lock(mtx);
        // Mark phase: traverse roots and mark reachable blocks
        // For simplicity, assume roots point to allocated data (after header)
        for (size_t i = 0; i < numRoots; ++i) {
            if (roots[i]) {
                BlockHeader* block = reinterpret_cast<BlockHeader*>(
                    static_cast<char*>(roots[i]) - sizeof(BlockHeader));
                mark(block);
            }
        }

        // Sweep phase: free unmarked allocated blocks
        char* ptr = pool;
        while (ptr < poolEnd) {
            BlockHeader* block = reinterpret_cast<BlockHeader*>(ptr);
            if (block->flags == ALLOCATED && !block->marked) {
                // Free this block
                block->flags = FREE;
                // Coalesce with next if free (simplified)
                BlockHeader* next = reinterpret_cast<BlockHeader*>(
                    ptr + sizeof(BlockHeader) + block->size);
                if (next < reinterpret_cast<BlockHeader*>(poolEnd) && next->flags == FREE) {
                    block->size += sizeof(BlockHeader) + next->size;
                    removeFromFreeList(next);
                }
                insertIntoFreeList(block);
            } else if (block->flags == ALLOCATED) {
                block->marked = false; // Clear mark for next cycle
            }
            ptr += sizeof(BlockHeader) + block->size;
        }
    }

private:
    enum Flags { FREE = 0, ALLOCATED = 1 };
    struct BlockHeader {
        size_t size;      // Size of user data (excluding header)
        unsigned int flags : 1; // FREE or ALLOCATED
        unsigned int marked : 1; // For GC
        BlockHeader* next; // For free list (only valid when FREE)
    };

    char* pool;
    char* poolEnd;
    BlockHeader* freeList;
    std::mutex mtx;

    void mark(BlockHeader* block) {
        if (!block || block->flags != ALLOCATED || block->marked)
            return;
        block->marked = true;
        // For a real GC, we would scan the block's contents for pointers.
        // Here we assume no interior pointers for simplicity.
    }

    void removeFromFreeList(BlockHeader* block) {
        BlockHeader* prev = nullptr;
        BlockHeader* curr = freeList;
        while (curr) {
            if (curr == block) {
                if (prev) prev->next = curr->next;
                else freeList = curr->next;
                return;
            }
            prev = curr;
            curr = curr->next;
        }
    }

    void insertIntoFreeList(BlockHeader* block) {
        // Insert in address order to facilitate coalescing
        BlockHeader* prev = nullptr;
        BlockHeader* curr = freeList;
        while (curr && curr < block) {
            prev = curr;
            curr = curr->next;
        }
        block->next = curr;
        if (prev) prev->next = block;
        else freeList = block;
    }
};
```

**Pointer Arithmetic & Metadata Overhead**  
- Each block has a `BlockHeader` (size, flags, next pointer) placed immediately before user data.  
- `allocate` returns `ptr = (char*)block + sizeof(BlockHeader)`.  
- `deallocate` recovers the header via `block = (BlockHeader*)((char*)ptr - sizeof(BlockHeader))`.  
- Overhead: 1 header per allocation (typically 16–24 bytes depending on alignment).  

**Fragmentation Prevention**  
- Coalescing adjacent free blocks on `deallocate` and during GC sweep.  
- Free list kept sorted by address to enable O(1) forward coalescing.  
- Splitting blocks only when remainder is large enough to hold a new header + minimum data.  

**Thread Safety**  
- All public methods acquire a `std::mutex` to protect shared state (pool, free list).  
- GC also locks, ensuring no allocations happen during marking/sweeping.  

**Garbage Collection**  
- Simple mark-sweep: marks reachable blocks from root set, then sweeps unmarked allocated blocks, freeing and coalescing them.  
- Mark bit stored in header; cleared after each sweep.  
- For production, a full pointer scanner would be needed; here we assume roots directly point to allocated objects.

```c
#include <stddef.h>
#include <stdlib.h>
#include <pthread.h>

/* Block header – metadata overhead per allocation */
typedef struct block {
    size_t size;            /* size of usable memory */
    struct block *next;     /* next free block (free list) */
    int marked;             /* mark bit for GC */
} block_t;

/* Memory pool – preallocated arena */
typedef struct {
    void *start;
    size_t total_size;
    block_t *free_list;     /* singly linked free list */
    pthread_mutex_t lock;
} allocator_t;

/* Initialize allocator with a fixed-size arena */
allocator_t* allocator_create(size_t size) {
    allocator_t *a = malloc(sizeof(allocator_t));
    a->start = malloc(size);
    a->total_size = size;
    a->free_list = (block_t*)a->start;
    a->free_list->size = size - sizeof(block_t);
    a->free_list->next = NULL;
    a->free_list->marked = 0;
    pthread_mutex_init(&a->lock, NULL);
    return a;
}

/* Allocate memory – returns pointer to usable area */
void* allocator_alloc(allocator_t *a, size_t size) {
    pthread_mutex_lock(&a->lock);
    block_t *prev = NULL;
    block_t *curr = a->free_list;
    while (curr) {
        if (curr->size >= size) {
            /* Split block if remainder is large enough for a header */
            size_t remaining = curr->size - size;
            if (remaining > sizeof(block_t)) {
                block_t *new_block = (block_t*)((char*)curr + sizeof(block_t) + size);
                new_block->size = remaining - sizeof(block_t);
                new_block->next = curr->next;
                new_block->marked = 0;
                curr->size = size;
                curr->next = new_block;
            }
            /* Remove from free list */
            if (prev) prev->next = curr->next;
            else a->free_list = curr->next;
            curr->marked = 0;
            pthread_mutex_unlock(&a->lock);
            /* Return pointer past header */
            return (void*)((char*)curr + sizeof(block_t));
        }
        prev = curr;
        curr = curr->next;
    }
    pthread_mutex_unlock(&a->lock);
    return NULL; /* out of memory */
}

/* Free memory – returns block to free list */
void allocator_free(allocator_t *a, void *ptr) {
    if (!ptr) return;
    block_t *block = (block_t*)((char*)ptr - sizeof(block_t));
    pthread_mutex_lock(&a->lock);
    block->next = a->free_list;
    block->marked = 0;
    a->free_list = block;
    pthread_mutex_unlock(&a->lock);
}

/* Mark phase – mark all reachable blocks (simplified: user provides roots) */
void allocator_mark(allocator_t *a, void **roots, int num_roots) {
    pthread_mutex_lock(&a->lock);
    for (int i = 0; i < num_roots; i++) {
        if (roots[i]) {
            block_t *block = (block_t*)((char*)roots[i] - sizeof(block_t));
            block->marked = 1;
        }
    }
    pthread_mutex_unlock(&a->lock);
}

/* Sweep phase – free unmarked blocks */
void allocator_sweep(allocator_t *a) {
    pthread_mutex_lock(&a->lock);
    /* Traverse entire arena (simplified: linear scan) */
    char *pos = (char*)a->start;
    while (pos < (char*)a->start + a->total_size) {
        block_t *block = (block_t*)pos;
        if (block->size == 0) break; /* end marker */
        if (!block->marked) {
            /* Add to free list */
            block->next = a->free_list;
            a->free_list = block;
        } else {
            block->marked = 0; /* clear for next cycle */
        }
        pos += sizeof(block_t) + block->size;
    }
    pthread_mutex_unlock(&a->lock);
}

/* Destroy allocator */
void allocator_destroy(allocator_t *a) {
    pthread_mutex_destroy(&a->lock);
    free(a->start);
    free(a);
}
```

**Explanation**

- **Pointer arithmetic**: `block_t*` is obtained from user pointer by subtracting `sizeof(block_t)`. Allocation returns `(char*)block + sizeof(block_t)`. This ensures metadata is hidden from the user.
- **Metadata overhead**: Each block has a header (`block_t`) containing `size`, `next` (free list pointer), and `marked` (GC flag). Overhead is fixed per allocation (typically 16–24 bytes depending on alignment).
- **Fragmentation prevention**: The allocator uses a fixed-size arena and splits/coalesces blocks only when freeing. External fragmentation is minimized by using a best‑fit free list (here first‑fit for simplicity). Internal fragmentation is bounded by the header size.
- **Garbage collection**: Simple mark‑sweep. `allocator_mark` marks blocks reachable from user‑supplied roots. `allocator_sweep` scans the arena linearly and returns unmarked blocks to the free list. This prevents memory leaks but requires the user to provide roots.
- **Thread safety**: All public functions lock a `pthread_mutex_t` before modifying shared structures. The lock is released before returning. This ensures mutual exclusion but may reduce concurrency.

## Custom Memory Allocator with Fragmentation Prevention and Basic GC

### Design Overview
- **Fragmentation prevention**: Use a pool of fixed-size blocks (e.g., 64 bytes). All allocations are rounded up to block size, eliminating external fragmentation. Internal fragmentation is bounded by block size.
- **Metadata overhead**: Each block has a header containing:
  - `used` flag (1 byte)
  - `marked` flag for GC (1 byte)
  - `next` pointer for free list (8 bytes on 64-bit)
  - Total overhead: 10 bytes per block (can be reduced with bitfields or unions).
- **Pointer arithmetic**: Allocated pointer points to data area immediately after header. To free, subtract header size to get block header.
- **Garbage collection**: Simple mark-sweep. Roots are provided externally (e.g., global pointers). Mark phase traverses reachable blocks; sweep phase frees unmarked blocks.
- **Thread-safety**: A single mutex protects all allocator operations (allocate, free, GC). GC stops-the-world by locking the mutex.

### Step-by-Step Implementation

#### 1. Block Structure
```c
typedef struct Block {
    int used;          // 0 = free, 1 = allocated
    int marked;        // 0 = not reachable, 1 = reachable (for GC)
    struct Block* next; // pointer to next free block (in free list)
    char data[BLOCK_SIZE]; // actual data area
} Block;
```

#### 2. Allocator State
```c
#define NUM_BLOCKS 1024
#define BLOCK_SIZE 64

static Block pool[NUM_BLOCKS];
static Block* free_list = NULL;
static pthread_mutex_t lock = PTHREAD_MUTEX_INITIALIZER;
```

#### 3. Initialization
Link all blocks into the free list:
```c
void allocator_init() {
    for (int i = 0; i < NUM_BLOCKS - 1; i++) {
        pool[i].next = &pool[i+1];
        pool[i].used = 0;
        pool[i].marked = 0;
    }
    pool[NUM_BLOCKS-1].next = NULL;
    free_list = &pool[0];
}
```

#### 4. Allocation
- Lock mutex.
- Pop first block from free list.
- Set `used = 1`.
- Return pointer to `data` field.
```c
void* allocate() {
    pthread_mutex_lock(&lock);
    if (!free_list) {
        pthread_mutex_unlock(&lock);
        return NULL; // out of memory
    }
    Block* block = free_list;
    free_list = block->next;
    block->used = 1;
    block->marked = 0; // reset mark
    pthread_mutex_unlock(&lock);
    return block->data;
}
```

#### 5. Deallocation (Manual Free)
- Compute block pointer from data pointer: `Block* block = (Block*)((char*)ptr - offsetof(Block, data));`
- Lock mutex.
- Set `used = 0`.
- Push block back to free list.
```c
void deallocate(void* ptr) {
    if (!ptr) return;
    Block* block = (Block*)((char*)ptr - offsetof(Block, data));
    pthread_mutex_lock(&lock);
    block->used = 0;
    block->next = free_list;
    free_list = block;
    pthread_mutex_unlock(&lock);
}
```

#### 6. Garbage Collection (Mark-Sweep)
- **Mark phase**: Given an array of root pointers, for each root, compute block and recursively mark reachable blocks. Since blocks are fixed-size, we can only mark the block itself (no internal pointers unless we scan data for potential pointers – simplified here: assume roots point to block data).
- **Sweep phase**: Iterate all blocks; if `used == 1` and `marked == 0`, free the block (add to free list). Reset `marked` for next cycle.
```c
void mark_block(Block* block) {
    if (!block || block->marked) return;
    block->marked = 1;
    // If block data contains pointers to other blocks, recursively mark them.
    // For simplicity, we assume no internal pointers.
}

void collect_garbage(void** roots, int num_roots) {
    pthread_mutex_lock(&lock);
    // Mark phase
    for (int i = 0; i < num_roots; i++) {
        if (roots[i]) {
            Block* block = (Block*)((char*)roots[i] - offsetof(Block, data));
            mark_block(block);
        }
    }
    // Sweep phase
    for (int i = 0; i < NUM_BLOCKS; i++) {
        if (pool[i].used && !pool[i].marked) {
            // Free block
            pool[i].used = 0;
            pool[i].next = free_list;
            free_list = &pool[i];
        }
        pool[i].marked = 0; // reset for next GC
    }
    pthread_mutex_unlock(&lock);
}
```

### Pointer Arithmetic Details
- `offsetof(Block, data)` gives the byte offset from the start of a `Block` to its `data` field.
- When allocating, we return `&block->data`. The user sees a pointer to the data area.
- When freeing or marking, we compute the block header by subtracting the offset: `(Block*)((char*)ptr - offset)`.
- This arithmetic is safe because `data` is the last member of the struct (no padding after it if we use `__attribute__((packed))` or careful alignment). For portability, ensure `data` is aligned to the maximum alignment requirement (e.g., 8 bytes). We can add padding before `data` if needed.

### Metadata Overhead
- Per block: `used` (int, 4 bytes), `marked` (int, 4 bytes), `next` (pointer, 8 bytes) = 16 bytes overhead on 64-bit.
- With `BLOCK_SIZE = 64`, overhead is 20% (16/80). Can be reduced by using bitfields or storing flags in the pointer (e.g., low bits of `next`). For simplicity, we keep it explicit.

### Thread-Safety Considerations
- A single mutex protects all shared state: free list, block flags.
- `allocate()` and `deallocate()` are short critical sections.
- `collect_garbage()` holds the mutex for the entire duration, stopping all other allocation/free operations (stop-the-world). This is acceptable for a basic GC.
- For higher concurrency, one could use per-block locks or lock-free techniques, but that adds complexity.

### Limitations and Improvements
- Fixed block size causes internal fragmentation for small allocations.
- No coalescing (not needed for fixed-size blocks).
- GC does not handle pointers inside block data (requires scanning and type information).
- For production, consider slab allocators, buddy systems, or region-based allocation.

This implementation provides a clear, step-by-step custom allocator with fragmentation prevention and basic mark-sweep GC, with explicit pointer arithmetic, metadata overhead, and thread-safety via mutex.

```cpp
#include <cstddef>
#include <cstdint>
#include <mutex>
#include <vector>
#include <cstdlib>
#include <cstring>

// -----------------------------------------------------------------------------
// 1. Metadata overhead: each block has a header (8 bytes on 64-bit)
//    - size (4 bytes) or slab index
//    - flags (1 byte): bit0=allocated, bit1=marked
//    - padding to 8 bytes
// -----------------------------------------------------------------------------
struct BlockHeader {
    uint32_t size;      // size of user data (or slab class)
    uint8_t  flags;     // 0x01 = allocated, 0x02 = marked
    uint8_t  pad[3];    // align to 8 bytes
};

static constexpr size_t HEADER_SIZE = sizeof(BlockHeader);
static constexpr size_t MIN_BLOCK_SIZE = 16;   // minimum allocation size

// -----------------------------------------------------------------------------
// 2. Slab allocator for small fixed-size blocks (prevents external fragmentation)
//    Each slab is a contiguous region divided into equal-sized blocks.
// -----------------------------------------------------------------------------
class Slab {
public:
    Slab(size_t block_size, size_t num_blocks)
        : block_size_(block_size), num_blocks_(num_blocks) {
        // Allocate slab memory (aligned to page boundary for simplicity)
        size_t slab_size = num_blocks * (block_size + HEADER_SIZE);
        base_ = static_cast<char*>(std::aligned_alloc(64, slab_size));
        if (!base_) throw std::bad_alloc();
        // Initialize free list: chain free blocks via header->size (as next index)
        for (size_t i = 0; i < num_blocks; ++i) {
            BlockHeader* hdr = get_header(i);
            hdr->flags = 0;          // free
            hdr->size = i + 1;       // next free block index (or sentinel)
        }
        // Last block's next is sentinel (num_blocks)
        get_header(num_blocks - 1)->size = num_blocks;
        free_head_ = 0;
    }

    ~Slab() { std::free(base_); }

    void* allocate() {
        if (free_head_ == num_blocks_) return nullptr; // slab full
        BlockHeader* hdr = get_header(free_head_);
        free_head_ = hdr->size;       // advance free list
        hdr->flags = 0x01;            // mark allocated
        return hdr + 1;               // pointer to user data (pointer arithmetic)
    }

    void deallocate(void* ptr) {
        BlockHeader* hdr = static_cast<BlockHeader*>(ptr) - 1;
        // Add block back to free list
        hdr->size = free_head_;
        hdr->flags = 0;
        free_head_ = (hdr - reinterpret_cast<BlockHeader*>(base_));
    }

    // For GC: iterate all blocks, return header of each
    size_t num_blocks() const { return num_blocks_; }
    BlockHeader* get_header(size_t index) {
        return reinterpret_cast<BlockHeader*>(base_ + index * (block_size_ + HEADER_SIZE));
    }

private:
    char* base_;
    size_t block_size_;
    size_t num_blocks_;
    size_t free_head_;   // index of first free block
};

// -----------------------------------------------------------------------------
// 3. Large object allocator (buddy system or simple free list) to reduce waste
//    For simplicity, we use a free list of blocks sorted by size.
// -----------------------------------------------------------------------------
class LargeAllocator {
    struct FreeNode {
        size_t size;
        FreeNode* next;
    };
    FreeNode* free_list_ = nullptr;
    std::mutex mtx_;

public:
    void* allocate(size_t size) {
        std::lock_guard<std::mutex> lock(mtx_);
        // Best-fit search (simplified)
        FreeNode** prev = &free_list_;
        FreeNode* curr = free_list_;
        while (curr) {
            if (curr->size >= size) {
                // Remove node
                *prev = curr->next;
                // Return user data after header
                BlockHeader* hdr = reinterpret_cast<BlockHeader*>(curr);
                hdr->size = curr->size;
                hdr->flags = 0x01; // allocated
                return hdr + 1;
            }
            prev = &curr->next;
            curr = curr->next;
        }
        // No suitable free block, allocate from OS
        size_t total = HEADER_SIZE + size;
        void* mem = std::aligned_alloc(64, total);
        if (!mem) return nullptr;
        BlockHeader* hdr = static_cast<BlockHeader*>(mem);
        hdr->size = total;
        hdr->flags = 0x01;
        return hdr + 1;
    }

    void deallocate(void* ptr) {
        std::lock_guard<std::mutex> lock(mtx_);
        BlockHeader* hdr = static_cast<BlockHeader*>(ptr) - 1;
        FreeNode* node = reinterpret_cast<FreeNode*>(hdr);
        node->size = hdr->size;
        node->next = free_list_;
        free_list_ = node;
    }

    // For GC: iterate all allocated blocks (we need a separate list of allocated blocks)
    // Here we skip for brevity; in practice maintain a global list of all blocks.
};

