    // -------------------------------------------------------------------------
    void garbage_collect() {
        std::lock_guard<std::mutex> lock(global_mutex_);
        // --- Mark phase ---
        // For each root (e.g., global pointers, stack), call mark(ptr)
        // Here we assume a function mark_roots() that traverses known roots.
