        // --- Sweep phase ---
        // Iterate all slabs
        for (int i = 0; i < NUM_SLABS; ++i) {
            Slab* slab = slabs_[i];
            for (size_t j = 0; j < slab->num_blocks(); ++j) {
                BlockHeader* hdr = slab->get_header(j);
                if (hdr->flags & 0x01) { // allocated
