        // (omitted for brevity)
    }

    // Mark a single pointer (called during mark phase)
    void mark(void* ptr) {
        if (!ptr) return;
        BlockHeader* hdr = static_cast<BlockHeader*>(ptr) - 1;
        hdr->flags |= 0x02; // set mark bit
    }
