#include <cstring>
#include <mutex>
#include <cassert>

// Simple copying garbage collector with two semispaces.
// Prevents fragmentation by compacting live objects.
// Thread-safe via a global mutex.

class CopyingGC {
public:
    static constexpr size_t HEAP_SIZE = 64 * 1024; // 64KB per semispace

    // Object header: size (including header) and forwarding pointer.
    struct Header {
        size_t size;          // total bytes including header
        Header* forwarding;   // non-null if forwarded (points to new location)
    };

    CopyingGC() {
        fromSpace_ = static_cast<char*>(std::aligned_alloc(alignof(Header), HEAP_SIZE));
        toSpace_   = static_cast<char*>(std::aligned_alloc(alignof(Header), HEAP_SIZE));
        if (!fromSpace_ || !toSpace_) std::abort();
        reset();
    }

    ~CopyingGC() {
        std::free(fromSpace_);
        std::free(toSpace_);
    }

    // Allocate a block of `size` bytes (must be multiple of alignof(Header)).
    // Returns pointer to usable memory (after header).
    void* allocate(size_t size) {
        std::lock_guard<std::mutex> lock(mutex_);
        // Align size to header alignment
        size = (size + alignof(Header) - 1) & ~(alignof(Header) - 1);
        size_t total = size + sizeof(Header);
        if (bump_ + total > fromSpace_ + HEAP_SIZE) {
            collectGarbage();
            if (bump_ + total > fromSpace_ + HEAP_SIZE) {
                return nullptr; // out of memory after GC
            }
        }
        Header* hdr = reinterpret_cast<Header*>(bump_);
        hdr->size = total;
        hdr->forwarding = nullptr;
        bump_ += total;
        return hdr + 1; // return pointer after header
    }

    // Trigger garbage collection (public, but usually called automatically)
    void collectGarbage() {
        std::lock_guard<std::mutex> lock(mutex_);
        collectGarbageImpl();
    }

private:
    char* fromSpace_;
    char* toSpace_;
    char* bump_;          // current allocation pointer in fromSpace_
    std::mutex mutex_;

    void reset() {
        bump_ = fromSpace_;
        // Clear toSpace (not strictly necessary)
        std::memset(toSpace_, 0, HEAP_SIZE);
    }

    void collectGarbageImpl() {
        // Swap spaces
        std::swap(fromSpace_, toSpace_);
        char* newBump = fromSpace_; // start of new fromSpace (old toSpace)
        // We need to scan roots. For simplicity, assume we have a global root set.
        // In a real system, roots are stack/global variables.
        // Here we simulate with a static list of pointers.
        // For demonstration, we'll just copy all objects that are reachable.
        // Since we don't have a root set, we'll copy everything (full heap).
        // This is not a real GC but shows the mechanism.
        // In practice, you'd scan roots and recursively copy.

        // For this example, we'll copy all objects from old fromSpace (now toSpace)
        // to new fromSpace. This is a full compaction.
        char* scan = toSpace_; // old fromSpace (now toSpace)
        while (scan < toSpace_ + HEAP_SIZE) {
            Header* hdr = reinterpret_cast<Header*>(scan);
            if (hdr->size == 0) break; // end of used memory (bump pointer)
            // Copy object to new space
            Header* newHdr = reinterpret_cast<Header*>(newBump);
            std::memcpy(newHdr, hdr, hdr->size);
            // Set forwarding pointer in old object
            hdr->forwarding = newHdr;
            // Update any pointers inside the object (if we knew where they are)
            // For simplicity, we skip pointer fixup. In a real GC, you'd scan
            // the object's pointer fields and update them using forwarding.
            newBump += hdr->size;
            scan += hdr->size;
        }
        // Update bump pointer
        bump_ = newBump;
        // Clear old toSpace (now toSpace_ after swap) - not needed but safe
        std::memset(toSpace_, 0, HEAP_SIZE);
    }
};

// Example usage
struct Node {
    int value;
    Node* next;
};

int main() {
    CopyingGC gc;
    Node* n1 = static_cast<Node*>(gc.allocate(sizeof(Node)));
    Node* n2 = static_cast<Node*>(gc.allocate(sizeof(Node)));
    n1->value = 1;
    n1->next = n2;
    n2->value = 2;
    n2->next = nullptr;

    // Trigger GC (would normally happen automatically)
    gc.collectGarbage();

    // After GC, pointers are still valid because we didn't update them.
    // In a real implementation, we would need to fix up pointers.
    // This example demonstrates the structure but not full pointer fixup.
    return 0;
}
