**Explanation**

- **Pointer Arithmetic**: The allocator returns a pointer to the memory after the `Header`. During garbage collection, objects are copied from the old semispace to the new one. The old header’s `forwarding` field points to the new location. To update pointers, the collector must scan each object’s pointer fields (using a type descriptor or conservative scanning) and replace them with the forwarding address. This requires precise knowledge of pointer offsets.

- **Metadata Overhead**: Each object has an 8‑byte header (on 64‑bit) containing `size` and `forwarding`. This is the minimum overhead for compaction and allocation. Additional overhead may come from alignment padding.

- **Thread‑Safety**: A `std::mutex` protects allocation and garbage collection. All public methods lock the mutex. This ensures that only one thread allocates or collects at a time. For higher concurrency, a lock‑free approach or per‑thread heaps could be used.

- **Fragmentation Prevention**: The copying collector compacts all live objects into a contiguous block, eliminating external fragmentation. Internal fragmentation is minimized by aligning allocations to the header size.

- **Basic Garbage Collection**: The `collectGarbageImpl` function copies all objects from the old semispace to the new one. In a real system, it would start from a set of root pointers and recursively copy reachable objects, updating pointers via the forwarding pointer. The example omits pointer fixup for brevity but shows the core compaction mechanism.

```c
#include <stdlib.h>
#include <string.h>
#include <pthread.h>
#include <stdint.h>
#include <stdbool.h>

/* Configuration */
#define HEAP_SIZE (1024 * 1024)  /* 1 MB heap */
#define ALIGNMENT 8              /* 8-byte alignment */

/* Block header: stored before each allocated block */
typedef struct BlockHeader {
    size_t size;          /* total block size including header */
    bool   marked;        /* mark bit for GC */
    struct BlockHeader* next; /* for free list or all-blocks list */
} BlockHeader;

/* Heap memory */
static char heap[HEAP_SIZE];
static BlockHeader* free_list = NULL;   /* free blocks sorted by address */
static BlockHeader* all_blocks = NULL;  /* all allocated blocks (for GC) */
static pthread_mutex_t alloc_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Initialize heap: create one large free block */
static void init_heap(void) {
    if (free_list != NULL) return; /* already initialized */
    BlockHeader* first = (BlockHeader*)heap;
    first->size = HEAP_SIZE;
    first->marked = false;
    first->next = NULL;
    free_list = first;
    all_blocks = NULL;
}

/* Coalesce adjacent free blocks */
static void coalesce(BlockHeader* prev, BlockHeader* curr) {
    while (curr && curr->next) {
        BlockHeader* next = curr->next;
        if ((char*)curr + curr->size == (char*)next) {
            curr->size += next->size;
            curr->next = next->next;
        } else {
            break;
        }
    }
}

/* Allocate memory */
void* my_malloc(size_t size) {
    pthread_mutex_lock(&alloc_mutex);
    init_heap();

    /* Align size to ALIGNMENT and add header overhead */
    size_t aligned_size = (size + ALIGNMENT - 1) & ~(ALIGNMENT - 1);
    size_t total_size = aligned_size + sizeof(BlockHeader);
    if (total_size < sizeof(BlockHeader) + ALIGNMENT) total_size = sizeof(BlockHeader) + ALIGNMENT;

    /* First-fit search */
    BlockHeader* prev = NULL;
    BlockHeader* curr = free_list;
    while (curr) {
        if (curr->size >= total_size) {
            /* Split if remainder is large enough for a block */
            size_t remainder = curr->size - total_size;
            if (remainder >= sizeof(BlockHeader) + ALIGNMENT) {
                BlockHeader* new_block = (BlockHeader*)((char*)curr + total_size);
                new_block->size = remainder;
                new_block->marked = false;
                new_block->next = curr->next;
                curr->size = total_size;
                curr->next = new_block;
            }
            /* Remove from free list */
            if (prev) prev->next = curr->next;
            else free_list = curr->next;
            curr->next = NULL;

            /* Add to all_blocks list */
            curr->marked = false;
            curr->next = all_blocks;
            all_blocks = curr;

            pthread_mutex_unlock(&alloc_mutex);
            return (void*)((char*)curr + sizeof(BlockHeader));
        }
        prev = curr;
        curr = curr->next;
    }
    pthread_mutex_unlock(&alloc_mutex);
    return NULL; /* out of memory */
}

/* Free memory */
void my_free(void* ptr) {
    if (!ptr) return;
    pthread_mutex_lock(&alloc_mutex);

    BlockHeader* block = (BlockHeader*)((char*)ptr - sizeof(BlockHeader));

    /* Remove from all_blocks list */
    BlockHeader** prevp = &all_blocks;
    while (*prevp && *prevp != block) prevp = &(*prevp)->next;
    if (*prevp) *prevp = block->next;

    /* Insert into free list (sorted by address) */
    BlockHeader** fp = &free_list;
    while (*fp && *fp < block) fp = &(*fp)->next;
    block->next = *fp;
    *fp = block;

    /* Coalesce with neighbors */
    coalesce(NULL, free_list); /* simple: coalesce entire list */
    pthread_mutex_unlock(&alloc_mutex);
}

/* Mark phase: mark all reachable blocks from roots */
static void mark(BlockHeader** roots, int num_roots) {
    /* Simple mark: for each root pointer, find the block and mark it */
    for (int i = 0; i < num_roots; i++) {
        void* ptr = (void*)roots[i];
        if (!ptr) continue;
        /* Find block containing ptr (must be within heap) */
        if ((char*)ptr < heap || (char*)ptr >= heap + HEAP_SIZE) continue;
        BlockHeader* block = (BlockHeader*)((char*)ptr - sizeof(BlockHeader));
        block->marked = true;
    }
}

/* Sweep phase: free unmarked blocks */
static void sweep(void) {
    BlockHeader** prevp = &all_blocks;
    while (*prevp) {
        BlockHeader* block = *prevp;
        if (!block->marked) {
            /* Remove from all_blocks and add to free list */
            *prevp = block->next;
            block->marked = false;
            /* Insert into free list (sorted) */
            BlockHeader** fp = &free_list;
            while (*fp && *fp < block) fp = &(*fp)->next;
            block->next = *fp;
            *fp = block;
            /* Coalesce after insertion */
            coalesce(NULL, free_list);
        } else {
            block->marked = false; /* clear mark for next GC */
            prevp = &block->next;
        }
    }
}

/* Garbage collection: mark-sweep */
void my_gc(BlockHeader** roots, int num_roots) {
    pthread_mutex_lock(&alloc_mutex);
    mark(roots, num_roots);
    sweep();
    pthread_mutex_unlock(&alloc_mutex);
}
```

### Explanation

**Pointer Arithmetic**  
- Each allocation returns a pointer immediately after the `BlockHeader`.  
- To free, subtract `sizeof(BlockHeader)` from the user pointer to get the block header.  
- Coalescing uses `(char*)curr + curr->size == (char*)next` to check adjacency.

**Metadata Overhead**  
- Each block has a 3-field header: `size` (size_t), `marked` (bool), `next` (pointer).  
- On 64-bit systems: 8+1+8 = 17 bytes, padded to 24 bytes due to alignment.  
- Overhead is at least `sizeof(BlockHeader)` per allocation (typically 16–24 bytes).

**Thread-Safety**  
- A single `pthread_mutex_t` protects all allocator state (free list, all_blocks list).  
- All public functions (`my_malloc`, `my_free`, `my_gc`) lock the mutex.  
- The GC must also lock to avoid concurrent allocation/free during mark-sweep.  
- This simple mutex ensures correctness but limits concurrency; a more advanced allocator could use per-thread caches or fine-grained locking.

**Fragmentation Prevention**  
- Free blocks are coalesced after every free and after GC sweep.  
- First-fit allocation with splitting reduces external fragmentation.  
- The segregated free list (sorted by address) enables efficient coalescing.  
- GC reclaims cycles and unreachable objects, preventing memory leaks that cause fragmentation over time.

```c
#include <cstddef>
#include <cstdlib>
#include <cstring>
#include <mutex>
#include <vector>
#include <cassert>

// Simple handle-based compacting garbage collector
class CompactAllocator {
public:
    struct Header {
        size_t size;      // size of user data (excluding header)
        bool marked;      // for GC mark phase
    };

    // Handle: index into handle table
    using Handle = size_t;

private:
    static const size_t HEAP_SIZE = 1024 * 1024; // 1 MB
    char* heap_start;
    char* heap_end;
    char* free_ptr;       // next free address (bump allocator during normal allocation)

    // Handle table: each entry points to the actual object in the heap
    struct HandleEntry {
        char* ptr;        // pointer to object data (after header)
        bool active;
    };
    std::vector<HandleEntry> handle_table;
    std::vector<size_t> free_handles; // recycled handle indices

    std::mutex mtx;       // thread safety

    // Mark phase: recursively mark objects reachable from roots
    void mark(Handle h) {
        if (h == 0 || !handle_table[h].active) return;
        char* obj = handle_table[h].ptr;
        Header* hdr = reinterpret_cast<Header*>(obj - sizeof(Header));
        if (hdr->marked) return;
        hdr->marked = true;
        // For simplicity, assume objects contain only handles (size_t)
        // In real code, you'd need type info to traverse fields.
        size_t num_handles = hdr->size / sizeof(Handle);
        Handle* fields = reinterpret_cast<Handle*>(obj);
        for (size_t i = 0; i < num_handles; ++i) {
            mark(fields[i]);
        }
    }

    // Compact phase: slide live objects to the left, update handle table
    void compact() {
        char* dest = heap_start;
        for (auto& entry : handle_table) {
            if (!entry.active) continue;
            char* obj = entry.ptr;
            Header* hdr = reinterpret_cast<Header*>(obj - sizeof(Header));
            if (!hdr->marked) continue; // should not happen after sweep
            size_t total_size = sizeof(Header) + hdr->size;
            if (dest != obj - sizeof(Header)) {
                // Move object to dest
                std::memmove(dest, obj - sizeof(Header), total_size);
                // Update handle to point to new location
                entry.ptr = dest + sizeof(Header);
            }
            dest += total_size;
            // Clear mark for next GC
            hdr = reinterpret_cast<Header*>(dest - total_size);
            hdr->marked = false;
        }
        free_ptr = dest;
    }

public:
    CompactAllocator() {
        heap_start = static_cast<char*>(std::malloc(HEAP_SIZE));
        heap_end = heap_start + HEAP_SIZE;
        free_ptr = heap_start;
        // Handle 0 is reserved as null
        handle_table.push_back({nullptr, false});
    }

    ~CompactAllocator() {
        std::free(heap_start);
    }

    // Allocate memory, return handle
    Handle allocate(size_t size) {
        std::lock_guard<std::mutex> lock(mtx);
        // Align size to 8 bytes
        size = (size + 7) & ~7;
        size_t total = sizeof(Header) + size;
        if (free_ptr + total > heap_end) {
            // Trigger GC
            collectGarbage();
            if (free_ptr + total > heap_end) {
                return 0; // out of memory
            }
        }
        Header* hdr = reinterpret_cast<Header*>(free_ptr);
        hdr->size = size;
        hdr->marked = false;
        char* user_ptr = free_ptr + sizeof(Header);
        free_ptr += total;

        // Create handle
        Handle h;
        if (!free_handles.empty()) {
            h = free_handles.back();
            free_handles.pop_back();
            handle_table[h] = {user_ptr, true};
        } else {
            h = handle_table.size();
            handle_table.push_back({user_ptr, true});
        }
        return h;
    }

    // Get pointer from handle (for reading/writing)
    void* getPointer(Handle h) {
        if (h == 0 || h >= handle_table.size() || !handle_table[h].active)
            return nullptr;
        return handle_table[h].ptr;
    }

    // Free a handle (mark as inactive, but memory not reclaimed until GC)
    void free(Handle h) {
        std::lock_guard<std::mutex> lock(mtx);
        if (h == 0 || h >= handle_table.size() || !handle_table[h].active)
            return;
        handle_table[h].active = false;
        free_handles.push_back(h);
    }

    // Garbage collection: mark-sweep-compact
    void collectGarbage() {
        // Mark from roots (user must provide roots via setRoots, here we assume all active handles are roots)
        // In a real system, you'd have a root set (stack, globals). For simplicity, we mark all active handles.
        for (size_t i = 1; i < handle_table.size(); ++i) {
            if (handle_table[i].active) {
                mark(i);
            }
        }
        // Sweep: unmarked objects become free; we compact only live ones
        // We'll compact all live objects to the left
        compact();
        // After compaction, free_ptr is updated; all free space is after it.
        // Also, any handle that was not marked (should not happen because we marked all active) is removed.
        // But if we had handles that were freed (active=false), they are already removed from handle_table? No, we keep them.
        // For simplicity, we don't reclaim handle table entries here.
    }
};

// Example usage
int main() {
    CompactAllocator alloc;

    // Allocate an object containing two handles (simulating a struct with two pointers)
    CompactAllocator::Handle obj1 = alloc.allocate(2 * sizeof(CompactAllocator::Handle));
    CompactAllocator::Handle* fields = static_cast<CompactAllocator::Handle*>(alloc.getPointer(obj1));
    // Allocate two more objects
    CompactAllocator::Handle a = alloc.allocate(64);
    CompactAllocator::Handle b = alloc.allocate(64);
    fields[0] = a;
    fields[1] = b;

    // Free one of them
    alloc.free(b);

    // Trigger GC (compaction will move objects, handles are updated automatically)
    alloc.collectGarbage();

    // After GC, handles are still valid
    void* ptr_a = alloc.getPointer(a);
    // ptr_a points to the moved object
    return 0;
}
```

**Explanation**

- **Pointer arithmetic**: The allocator uses handles (indices into a handle table) instead of raw pointers. This allows the garbage collector to move objects during compaction without invalidating user references. The handle table entry is updated to point to the new location. User code accesses objects via `getPointer(handle)`, which returns the current address. Pointer arithmetic on the returned pointer is safe only within the same GC cycle; after a collection, the pointer must be re-fetched.

- **Metadata overhead**: Each allocation has a `Header` (size + mark bit) placed immediately before the user data. The header size is `sizeof(Header)` (typically 16 bytes on 64-bit). This is the only per-object overhead. The handle table adds an extra indirection and memory for each live handle (8 bytes for pointer + 1 byte active flag, plus vector overhead). This is a trade-off for compaction safety.

- **Thread-safety**: A single `std::mutex` protects all allocator operations (`allocate`, `free`, `collectGarbage`). This ensures mutual exclusion but may become a bottleneck. For higher concurrency, a lock-free approach or per-thread caches could be added.

- **Fragmentation prevention**: The compact phase slides all live objects to the beginning of the heap, eliminating external fragmentation. The free space is always a contiguous block at the end. Internal fragmentation is minimized by aligning allocations to 8 bytes.

- **Garbage collection**: A simple mark-sweep-compact collector. The mark phase traverses all active handles (treated as roots) and recursively marks objects reachable via handle fields. The sweep phase is combined with compaction: unmarked objects are overwritten by live ones. After compaction, all free space is contiguous. The example assumes objects contain only handles; a real implementation would require type metadata to traverse arbitrary fields.

```c
#include <stdlib.h>
#include <string.h>
#include <pthread.h>

/* ============================================================
   Custom memory allocator with compaction and mark-sweep GC
   ============================================================ */

/* Heap size – adjust as needed */
#define HEAP_SIZE (1024 * 1024)  /* 1 MB */

/* Minimum alignment (must be power of two) */
#define ALIGNMENT 8

/* Object header – stored before each allocated block */
typedef struct header {
    size_t size;          /* size of user data (multiple of ALIGNMENT) */
    unsigned int marked;  /* 1 if reachable, 0 otherwise */
    struct header *next;  /* link for free list / object list */
} header_t;

/* Heap memory and allocator state */
static char heap[HEAP_SIZE];
static header_t *free_list = NULL;   /* singly linked list of free blocks */
static header_t *object_list = NULL; /* all allocated objects (for GC) */
static pthread_mutex_t lock = PTHREAD_MUTEX_INITIALIZER;

/* ------------------------------------------------------------------
   Helper: align size to ALIGNMENT bytes
   ------------------------------------------------------------------ */
static inline size_t align_up(size_t size) {
    return (size + ALIGNMENT - 1) & ~(ALIGNMENT - 1);
}

/* ------------------------------------------------------------------
   Initialize the allocator – called once before any allocation
   ------------------------------------------------------------------ */
void mem_init(void) {
    /* The whole heap is one free block */
    free_list = (header_t *)heap;
    free_list->size = HEAP_SIZE - sizeof(header_t);
    free_list->marked = 0;
    free_list->next = NULL;
    object_list = NULL;
}

/* ------------------------------------------------------------------
   Allocate a block of 'size' bytes. Returns NULL on failure.
   ------------------------------------------------------------------ */
void *mem_alloc(size_t size) {
    if (size == 0) return NULL;

    size = align_up(size);
    size_t total = sizeof(header_t) + size;  /* header + user data */

    pthread_mutex_lock(&lock);

    /* First-fit search */
    header_t *prev = NULL;
    header_t *curr = free_list;
    while (curr) {
        if (curr->size >= total) {
            /* Found a suitable block */
            if (curr->size > total + sizeof(header_t)) {
                /* Split: create a new free block after the allocated part */
                header_t *new_free = (header_t *)((char *)curr + total);
                new_free->size = curr->size - total;
                new_free->marked = 0;
                new_free->next = curr->next;
                curr->size = size;  /* user data size */
                curr->next = new_free;
            } else {
                /* Exact fit or too small to split – use whole block */
                curr->size = size;
                /* Remove from free list */
                if (prev) prev->next = curr->next;
                else free_list = curr->next;
                curr->next = NULL;
            }

            /* Insert into object list (for GC) */
            curr->marked = 0;
            curr->next = object_list;
            object_list = curr;

            pthread_mutex_unlock(&lock);
            return (void *)(curr + 1);  /* pointer after header */
        }
        prev = curr;
        curr = curr->next;
    }

    /* No suitable block – trigger garbage collection */
    pthread_mutex_unlock(&lock);
    mem_gc();
    /* Retry after GC */
    return mem_alloc(size);
}

/* ------------------------------------------------------------------
   Mark phase: recursively mark all reachable objects.
   For simplicity, we assume roots are passed as an array of pointers.
   ------------------------------------------------------------------ */
static void mark_object(void *ptr) {
    if (!ptr) return;
    header_t *hdr = (header_t *)ptr - 1;
    if (hdr->marked) return;  /* already marked */
    hdr->marked = 1;

    /* For a real GC, we would scan the object's fields for pointers.
       Here we assume the object contains no pointers (toy example). */
}

void mem_mark_roots(void **roots, int n) {
    pthread_mutex_lock(&lock);
    for (int i = 0; i < n; i++) {
        mark_object(roots[i]);
    }
    pthread_mutex_unlock(&lock);
}

/* ------------------------------------------------------------------
   Sweep and compact phase:
   1. Sweep: free unmarked objects, rebuild free list.
   2. Compact: move all marked objects to the beginning of the heap,
      updating pointers (not shown here – requires pointer map).
   For simplicity, we only do sweep (no compaction) in this example.
   ------------------------------------------------------------------ */
void mem_gc(void) {
    pthread_mutex_lock(&lock);

    /* Sweep: iterate object list, free unmarked blocks */
    header_t *prev_obj = NULL;
    header_t *curr_obj = object_list;
    while (curr_obj) {
        if (!curr_obj->marked) {
            /* Unmarked – add to free list */
            header_t *next_obj = curr_obj->next;
            /* Remove from object list */
            if (prev_obj) prev_obj->next = next_obj;
            else object_list = next_obj;

            /* Insert into free list (coalesce with adjacent free blocks) */
            curr_obj->size = curr_obj->size;  /* keep user size? Actually we need total block size */
            /* For simplicity, we just insert at head of free list (no coalesce) */
            curr_obj->next = free_list;
            free_list = curr_obj;

            curr_obj = next_obj;
        } else {
            /* Marked – clear mark for next GC */
            curr_obj->marked = 0;
            prev_obj = curr_obj;
            curr_obj = curr_obj->next;
        }
    }

    /* Coalesce adjacent free blocks (simple linear scan) */
    header_t *prev = NULL;
    header_t *curr = free_list;
    while (curr) {
        header_t *next = curr->next;
        if (next && ((char *)curr + sizeof(header_t) + curr->size) == (char *)next) {
            /* Merge curr and next */
            curr->size += sizeof(header_t) + next->size;
            curr->next = next->next;
            continue;  /* re-check with same curr */
        }
        prev = curr;
        curr = curr->next;
    }

    pthread_mutex_unlock(&lock);
}

/* ------------------------------------------------------------------
   Pointer arithmetic and metadata overhead explanation:
   - Each allocation returns a pointer to the user data area, which is
     located immediately after the header. The header is sizeof(header_t)
     bytes (typically 16–24 bytes on 64-bit systems).
   - To go from user pointer to header: (header_t*)ptr - 1.
   - To go from header to user data: (void*)(header + 1).
   - Alignment: user data is aligned to ALIGNMENT (8 bytes) because the
     header itself is aligned (heap start is aligned) and the user data
     starts at offset sizeof(header_t) which is a multiple of ALIGNMENT
     (since header_t is padded to 8 or 16 bytes).
   - Metadata overhead per allocation: sizeof(header_t) + possible
     internal fragmentation (due to alignment rounding).
   ------------------------------------------------------------------ */

/* ------------------------------------------------------------------
   Thread-safety:
   - All public functions (mem_alloc, mem_gc, mem_mark_roots) acquire
     a global mutex before modifying shared state.
   - The mutex is initialized statically.
   - This ensures mutual exclusion but may reduce concurrency.
     For higher performance, one could use per‑heap locks or lock‑free
     techniques, but that is beyond this basic example.
   ------------------------------------------------------------------ */
```

```c
#include <stdlib.h>
#include <string.h>
#include <pthread.h>

/* Configuration */
#define POOL_SIZE 1024 * 1024        /* 1 MB pool */
#define BLOCK_SIZE 64                /* fixed block size */
#define NUM_BLOCKS (POOL_SIZE / (BLOCK_SIZE + sizeof(BlockHeader)))

/* Metadata per block */
typedef struct BlockHeader {
    int in_use;          /* 1 if allocated, 0 if free */
    int marked;          /* for GC mark phase */
    struct BlockHeader *next; /* for free list / GC list */
} BlockHeader;

/* Memory pool and free list */
static char pool[POOL_SIZE];
static BlockHeader *free_list = NULL;
static pthread_mutex_t alloc_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Initialize allocator: build free list */
void mem_init() {
    pthread_mutex_lock(&alloc_mutex);
    for (int i = 0; i < NUM_BLOCKS; i++) {
        BlockHeader *hdr = (BlockHeader *)(pool + i * (BLOCK_SIZE + sizeof(BlockHeader)));
        hdr->in_use = 0;
        hdr->marked = 0;
        hdr->next = free_list;
        free_list = hdr;
    }
    pthread_mutex_unlock(&alloc_mutex);
}

/* Allocate a block */
void *mem_alloc() {
    pthread_mutex_lock(&alloc_mutex);
    if (!free_list) {
        pthread_mutex_unlock(&alloc_mutex);
        return NULL; /* out of memory */
    }
    BlockHeader *hdr = free_list;
    free_list = hdr->next;
    hdr->in_use = 1;
    hdr->marked = 0;
    void *ptr = (void *)(hdr + 1); /* pointer arithmetic: skip header */
    pthread_mutex_unlock(&alloc_mutex);
    return ptr;
}

/* Deallocate a block */
void mem_free(void *ptr) {
    if (!ptr) return;
    BlockHeader *hdr = (BlockHeader *)ptr - 1; /* pointer arithmetic: go back to header */
    pthread_mutex_lock(&alloc_mutex);
    hdr->in_use = 0;
    hdr->marked = 0;
    hdr->next = free_list;
    free_list = hdr;
    pthread_mutex_unlock(&alloc_mutex);
}

/* Mark phase: user provides root pointers */
void mem_mark(void **roots, int num_roots) {
    pthread_mutex_lock(&alloc_mutex);
    /* Simple mark: iterate roots and mark the block they point to */
    for (int i = 0; i < num_roots; i++) {
        void *ptr = roots[i];
        if (ptr >= (void*)(pool + sizeof(BlockHeader)) && ptr < (void*)(pool + POOL_SIZE)) {
            BlockHeader *hdr = (BlockHeader *)ptr - 1;
            hdr->marked = 1;
        }
    }
    pthread_mutex_unlock(&alloc_mutex);
}

/* Sweep phase: free unmarked blocks */
void mem_sweep() {
    pthread_mutex_lock(&alloc_mutex);
    for (int i = 0; i < NUM_BLOCKS; i++) {
        BlockHeader *hdr = (BlockHeader *)(pool + i * (BLOCK_SIZE + sizeof(BlockHeader)));
        if (hdr->in_use && !hdr->marked) {
            /* Free this block */
            hdr->in_use = 0;
            hdr->marked = 0;
            hdr->next = free_list;
            free_list = hdr;
        } else if (hdr->in_use) {
            /* Reset mark for next cycle */
            hdr->marked = 0;
        }
    }
    pthread_mutex_unlock(&alloc_mutex);
}

/* Combined garbage collection */
void mem_gc(void **roots, int num_roots) {
    mem_mark(roots, num_roots);
    mem_sweep();
}

/* Example usage */
#include <stdio.h>
int main() {
    mem_init();
    void *a = mem_alloc();
    void *b = mem_alloc();
    void *c = mem_alloc();
    /* Use blocks... */
    mem_free(b); /* explicit free */
    /* Now a and c are still in use */
    void *roots[] = {a, c};
    mem_gc(roots, 2); /* collects any unreachable blocks (none here) */
    printf("Allocator works.\n");
    return 0;
}
```

**Explanation**

- **Pointer arithmetic**: Each allocation returns a pointer to the user data area, which is immediately after the `BlockHeader`. To get the header from a user pointer, subtract `sizeof(BlockHeader)` bytes. To get the user pointer from a header, add one `BlockHeader` size. This is done via `(BlockHeader *)ptr - 1` and `(void *)(hdr + 1)`.

- **Metadata overhead**: Each block has a `BlockHeader` (12 bytes on 32-bit, 16 on 64-bit due to pointer alignment). For a 64-byte block, overhead is ~20% (16/80). This is fixed and prevents external fragmentation because all blocks are the same size.

- **Thread-safety**: A single `pthread_mutex_t` protects all allocator operations (init, alloc, free, mark, sweep). This ensures mutual exclusion but may become a bottleneck. For higher concurrency, use per-thread caches or lock-free techniques.

- **Fragmentation prevention**: Fixed-size blocks eliminate external fragmentation. Internal fragmentation is bounded by `BLOCK_SIZE - requested_size` (if user requests less than block size). The allocator always returns a full block.

- **Garbage collection**: Simple mark-sweep. The user provides root pointers; the mark phase sets `marked` flag on reachable blocks. The sweep phase frees any `in_use` block that is not marked. After sweep, all unmarked blocks are returned to the free list. This requires the user to correctly identify roots and not modify pointers without updating roots.

## Custom Memory Allocator with Fragmentation Prevention and Basic GC

### Design Overview
- **Fixed-size block pool** to eliminate external fragmentation.
- **Free list** for O(1) allocation/deallocation.
- **Mark-sweep garbage collector** for automatic reclamation.
- **Mutex** for thread safety.

### Step 1: Block Structure and Metadata Overhead
Each block has a header containing:
- `bool in_use` (1 byte) – marks allocated/free.
- `bool marked` (1 byte) – used by GC.
- Padding to align to pointer size (e.g., 6 bytes on 64-bit) – ensures returned pointer is aligned.
- When free, the block's data area stores a `next` pointer to the next free block (reuses memory, no extra overhead).

Total overhead per block: **16 bytes** (on 64-bit) – 2 bytes flags + 6 padding + 8 bytes for free list pointer (only when free). This is acceptable for a pool allocator.

### Step 2: Pointer Arithmetic
- Allocation: pop a block from free list → set `in_use = true` → return `(void*)(block + sizeof(Header))`.
- Deallocation: given user pointer `p`, compute block start: `Header* h = (Header*)((char*)p - sizeof(Header))` → set `in_use = false` → push block onto free list.
- GC marking: traverse roots, for each pointer compute block start using same arithmetic, set `marked = true`.

### Step 3: Thread Safety
- A `std::mutex` protects the free list and block metadata.
- All allocation/free/GC operations lock the mutex.
- GC is stop-the-world: lock mutex, mark, sweep, unlock.

### Step 4: Garbage Collection (Mark-Sweep)
- **Roots**: a global list of `void**` pointers (e.g., stack roots registered by user).
- **Mark**: recursively follow pointers from roots, marking reachable blocks.
- **Sweep**: iterate all blocks; if `marked == false` and `in_use == true`, free the block; reset `marked` for next cycle.

### Implementation (C++)

```cpp
#include <iostream>
#include <mutex>
#include <vector>
#include <cstdint>

class PoolAllocator {
    struct Header {
        bool in_use;   // 1 byte
        bool marked;   // 1 byte
        // 6 bytes padding (implicit)
        // When free, the next 8 bytes store free list pointer
    };
    static_assert(sizeof(Header) == 16, "Header size must be 16 bytes");

    static constexpr size_t BLOCK_SIZE = 64;          // total block size (including header)
    static constexpr size_t DATA_SIZE = BLOCK_SIZE - sizeof(Header); // 48 bytes

    char* pool;                    // raw memory pool
    size_t num_blocks;
    void* free_list;               // linked list of free blocks
    std::mutex mtx;

    // Convert user pointer to block header
    Header* ptr_to_header(void* ptr) {
        return reinterpret_cast<Header*>(static_cast<char*>(ptr) - sizeof(Header));
    }

    // Convert block header to user pointer
    void* header_to_ptr(Header* h) {
        return static_cast<char*>(h) + sizeof(Header);
    }

public:
    PoolAllocator(size_t blocks) : num_blocks(blocks) {
        pool = new char[blocks * BLOCK_SIZE];
        free_list = nullptr;
        // Initialize free list
        for (size_t i = 0; i < blocks; ++i) {
            Header* h = reinterpret_cast<Header*>(pool + i * BLOCK_SIZE);
            h->in_use = false;
            h->marked = false;
            // Store next pointer in data area
            *reinterpret_cast<void**>(header_to_ptr(h)) = free_list;
            free_list = header_to_ptr(h);
        }
    }

    ~PoolAllocator() {
        delete[] pool;
    }

    void* allocate() {
        std::lock_guard<std::mutex> lock(mtx);
        if (!free_list) return nullptr; // out of memory
        void* ptr = free_list;
        Header* h = ptr_to_header(ptr);
        h->in_use = true;
        h->marked = false;
        free_list = *reinterpret_cast<void**>(ptr); // advance free list
        return ptr;
    }

    void deallocate(void* ptr) {
        if (!ptr) return;
        std::lock_guard<std::mutex> lock(mtx);
        Header* h = ptr_to_header(ptr);
        h->in_use = false;
        h->marked = false;
        // Push back to free list
        *reinterpret_cast<void**>(ptr) = free_list;
        free_list = ptr;
    }

    // Garbage collection: mark from roots, then sweep
    void collect(const std::vector<void*>& roots) {
        std::lock_guard<std::mutex> lock(mtx);
        // Mark phase
        for (void* root : roots) {
            mark(root);
        }
        // Sweep phase
        for (size_t i = 0; i < num_blocks; ++i) {
            Header* h = reinterpret_cast<Header*>(pool + i * BLOCK_SIZE);
            if (h->in_use && !h->marked) {
                // Unreachable block – free it
                h->in_use = false;
                void* ptr = header_to_ptr(h);
                *reinterpret_cast<void**>(ptr) = free_list;
                free_list = ptr;
            }
            h->marked = false; // reset for next cycle
        }
    }

private:
    void mark(void* ptr) {
        if (!ptr) return;
        // Check if pointer is within pool
        char* cptr = static_cast<char*>(ptr);
        if (cptr < pool || cptr >= pool + num_blocks * BLOCK_SIZE) return;
        // Align to block start
        size_t offset = (cptr - pool) % BLOCK_SIZE;
        if (offset != sizeof(Header)) return; // not a valid block start
        Header* h = reinterpret_cast<Header*>(cptr - sizeof(Header));
        if (!h->in_use || h->marked) return;
        h->marked = true;
        // For simplicity, assume data contains pointers; scan data area
        char* data = static_cast<char*>(header_to_ptr(h));
        for (size_t i = 0; i < DATA_SIZE; i += sizeof(void*)) {
            void* child = *reinterpret_cast<void**>(data + i);
            mark(child);
        }
    }
};
```

### Step 5: Usage Example
```cpp
int main() {
    PoolAllocator alloc(1000);
    void* p1 = alloc.allocate();
    void* p2 = alloc.allocate();
    // ... use p1, p2
    std::vector<void*> roots = {p1}; // assume p1 is a root
    alloc.collect(roots); // p2 will be freed if not reachable
    alloc.deallocate(p1);
    return 0;
}
```

### Key Points
- **No external fragmentation** – all blocks same size.
- **Internal fragmentation** – up to `DATA_SIZE - actual_use` bytes per allocation.
- **Pointer arithmetic** – safe conversion using `offsetof`-like calculation.
- **Thread safety** – mutex ensures atomic operations.
- **GC** – simple mark-sweep; requires user to supply roots; scanning assumes all data are pointers (impractical for production but illustrates concept).

```c
#include <stdlib.h>
#include <string.h>
#include <pthread.h>

// Custom allocator: region-based with compaction and mark-sweep GC
// Prevents external fragmentation by compacting live objects into a contiguous block.

#define ALIGNMENT 8
#define HEADER_SIZE (sizeof(BlockHeader))
#define MIN_BLOCK_SIZE (HEADER_SIZE + 1)

typedef struct BlockHeader {
    size_t size;          // includes header
    unsigned int marked;  // GC mark flag
    struct BlockHeader *next;
} BlockHeader;

typedef struct {
    void *start;
    size_t total_size;
    BlockHeader *free_list;  // sorted by address
    BlockHeader *used_list;  // all allocated blocks
    pthread_mutex_t lock;
} Arena;

// Initialize arena with a pre-allocated memory region
void arena_init(Arena *arena, void *mem, size_t size) {
    arena->start = mem;
    arena->total_size = size;
    arena->free_list = (BlockHeader*)mem;
    arena->free_list->size = size;
    arena->free_list->marked = 0;
    arena->free_list->next = NULL;
    arena->used_list = NULL;
    pthread_mutex_init(&arena->lock, NULL);
}

// Pointer arithmetic: given a block header, return usable memory address
static inline void *block_to_mem(BlockHeader *block) {
    return (void*)((char*)block + HEADER_SIZE);
}

// Given a memory pointer, get the block header (assumes pointer was returned by alloc)
static inline BlockHeader *mem_to_block(void *ptr) {
    return (BlockHeader*)((char*)ptr - HEADER_SIZE);
}

// Allocate memory (thread-safe)
void *arena_alloc(Arena *arena, size_t size) {
    pthread_mutex_lock(&arena->lock);
    // Align size
    size = (size + ALIGNMENT - 1) & ~(ALIGNMENT - 1);
    size_t needed = size + HEADER_SIZE;
    if (needed < MIN_BLOCK_SIZE) needed = MIN_BLOCK_SIZE;

    // First-fit search on free list
    BlockHeader *prev = NULL, *curr = arena->free_list;
    while (curr) {
        if (curr->size >= needed) {
            // Split if remainder is large enough
            size_t remaining = curr->size - needed;
            if (remaining >= MIN_BLOCK_SIZE) {
                BlockHeader *new_block = (BlockHeader*)((char*)curr + needed);
                new_block->size = remaining;
                new_block->marked = 0;
                new_block->next = curr->next;
                curr->size = needed;
                curr->next = new_block;
                if (prev) prev->next = new_block;
                else arena->free_list = new_block;
            } else {
                // Remove entire block from free list
                if (prev) prev->next = curr->next;
                else arena->free_list = curr->next;
            }
            // Add to used list (insert at head)
            curr->marked = 0;
            curr->next = arena->used_list;
            arena->used_list = curr;
            pthread_mutex_unlock(&arena->lock);
            return block_to_mem(curr);
        }
        prev = curr;
        curr = curr->next;
    }
    pthread_mutex_unlock(&arena->lock);
    return NULL; // Out of memory
}

// Free memory (marks block as free, but actual compaction happens during GC)
void arena_free(Arena *arena, void *ptr) {
    if (!ptr) return;
    pthread_mutex_lock(&arena->lock);
    BlockHeader *block = mem_to_block(ptr);
    // Remove from used list (simple linear search – for demo only)
    BlockHeader **prev_next = &arena->used_list;
    BlockHeader *curr = arena->used_list;
    while (curr) {
        if (curr == block) {
            *prev_next = curr->next;
            break;
        }
        prev_next = &curr->next;
        curr = curr->next;
    }
    // Add to free list (sorted by address for coalescing)
    BlockHeader *fp = arena->free_list, *fprev = NULL;
    while (fp && fp < block) {
        fprev = fp;
        fp = fp->next;
    }
    block->next = fp;
    if (fprev) fprev->next = block;
    else arena->free_list = block;
    // Coalesce with next if adjacent
    if (fp && (char*)block + block->size == (char*)fp) {
        block->size += fp->size;
        block->next = fp->next;
    }
    // Coalesce with previous if adjacent
    if (fprev && (char*)fprev + fprev->size == (char*)block) {
        fprev->size += block->size;
        fprev->next = block->next;
    }
    pthread_mutex_unlock(&arena->lock);
}

// Mark phase: traverse roots and mark reachable blocks
void arena_mark(Arena *arena, void **roots, int num_roots) {
    pthread_mutex_lock(&arena->lock);
    // Clear all marks in used list
    BlockHeader *curr = arena->used_list;
    while (curr) {
        curr->marked = 0;
        curr = curr->next;
    }
    // Mark from roots (assume roots point to memory inside blocks)
    for (int i = 0; i < num_roots; i++) {
        void *ptr = roots[i];
        if (ptr >= arena->start && ptr < (char*)arena->start + arena->total_size) {
            BlockHeader *block = mem_to_block(ptr);
            block->marked = 1;
        }
    }
    pthread_mutex_unlock(&arena->lock);
}

// Sweep + compact: move all marked blocks to the beginning, update pointers
void arena_sweep_compact(Arena *arena) {
    pthread_mutex_lock(&arena->lock);
    // First, collect all marked blocks from used list into a temporary list
    BlockHeader *marked = NULL, *marked_tail = NULL;
    BlockHeader *curr = arena->used_list;
    while (curr) {
        BlockHeader *next = curr->next;
        if (curr->marked) {
            curr->next = NULL;
            if (!marked) marked = curr;
            else marked_tail->next = curr;
            marked_tail = curr;
        } else {
            // Unmarked: add to free list (coalescing omitted for brevity)
            // For simplicity, just put them back into free list
            curr->next = arena->free_list;
            arena->free_list = curr;
        }
        curr = next;
    }
    arena->used_list = marked;

    // Compact: move marked blocks to the start of the arena
    char *dest = (char*)arena->start;
    curr = marked;
    while (curr) {
        size_t block_size = curr->size;
        // Move block data to dest (overlap-safe if we copy from low to high)
        memmove(dest, curr, block_size);
        // Update the block header pointer in the list
        BlockHeader *new_block = (BlockHeader*)dest;
        new_block->next = curr->next; // preserve list linkage
        // Update the previous block's next pointer if needed
        if (curr == marked) {
            marked = new_block;
        } else {
            // Find previous in list (we can keep a prev pointer)
            // For simplicity, we rebuild the list after compaction
        }
        dest += block_size;
        curr = curr->next;
    }
    // Rebuild used list with new addresses (simplified: just iterate and fix)
    // This is a placeholder; a full implementation would update all pointers.
    // For demonstration, we assume no external pointers need updating.
    // After compaction, the remaining free space is from dest to end.
    size_t used_size = dest - (char*)arena->start;
    size_t free_size = arena->total_size - used_size;
    if (free_size > 0) {
        BlockHeader *free_block = (BlockHeader*)dest;
        free_block->size = free_size;
        free_block->marked = 0;
        free_block->next = NULL;
        arena->free_list = free_block;
    } else {
        arena->free_list = NULL;
    }
    pthread_mutex_unlock(&arena->lock);
}

// Example usage
int main() {
    char memory[1024];
    Arena arena;
    arena_init(&arena, memory, sizeof(memory));

    int *a = (int*)arena_alloc(&arena, sizeof(int));
    int *b = (int*)arena_alloc(&arena, sizeof(int));
    *a = 42;
    *b = 99;

    // GC roots
    void *roots[] = { a };
    arena_mark(&arena, roots, 1);
    arena_sweep_compact(&arena); // b is reclaimed, a is moved

    // After compaction, a may have moved; pointer a is invalid.
    // In a real system, roots are updated via a handle or relocation table.
    // Here we just demonstrate the mechanism.

    arena_free(&arena, a); // free after use
    return 0;
}
```

**Explanation:**

- **Pointer arithmetic:** `block_to_mem` adds `HEADER_SIZE` to the block address to get usable memory. `mem_to_block` subtracts it. All addresses are relative to the arena base.
- **Metadata overhead:** Each block has a `BlockHeader` (size, marked flag, next pointer). Overhead is `HEADER_SIZE` bytes per allocation.
- **Thread-safety:** A single `pthread_mutex_t` protects all allocator operations. For higher concurrency, a lock-free design or per-size-class locks could be used.
- **Fragmentation prevention:** The allocator uses compaction during GC: live objects are moved to the beginning of the arena, eliminating external fragmentation. Coalescing on free also helps.
- **Garbage collection:** Mark-sweep with compaction. `arena_mark` marks reachable blocks from roots. `arena_sweep_compact` frees unmarked blocks and compacts live ones. Note: after compaction, all pointers to moved objects become invalid unless updated (e.g., via handles or a relocation table). The example simplifies this.
